def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        if ratio > 3:
            penalties = sum(((ratio - j) ** 3) * 1500 / (j ** 2) for j in range(2, 5))
            priorities[i] = 3000 + penalties
        elif 2 < ratio <= 3:
            base = 800 + (ratio - 2) * 250
            adjustments = 0
            for m in range(1, 5):
                adjustments += ((capacity * 0.9 - item) / (capacity + m)) ** 2 * 30 / (m + 1)
            priorities[i] = base + adjustments
        elif 1 < ratio <= 2:
            priorities[i] = 400 + (ratio - 1) * 120
            if (capacity - item) < 0.05 * capacity:
                priorities[i] -= 50
        elif ratio == 1:
            priorities[i] = 200 - np.log1p(capacity)
        else:
            score = 0
            for j in range(1, 15):
                temp = ((capacity - item) ** j) / (capacity ** j)
                if temp < 0.03:
                    score += temp * 150 / (j ** 1.5)
                elif 0.03 <= temp < 0.15:
                    score += temp * 30 / (j * 2)
                else:
                    score += temp * 8 / (j ** 2)
            if score < 0.04:
                priorities[i] = score * 25 + 5 / (capacity + 1)
            elif 0.04 <= score < 0.25:
                priorities[i] = 1 / (score + 0.3) + 0.1 * np.sin(item)
            else:
                adjustment = 0
                for k in range(1, 6):
                    adjustment += ((item / (capacity + k / 2)) ** k) * 12 / (k + 2)
                priorities[i] = 1 / (score + 0.8) + adjustment - 0.05 * i
        if (capacity - item) < 0.15 * capacity:
            priorities[i] += 0.05 * (capacity - item)
        if item > 0.85 * capacity:
            priorities[i] *= 0.85
        if i % 3 == 0:
            priorities[i] += np.sqrt(capacity + 1) / (item + 1)
        elif i % 3 == 1:
            priorities[i] -= np.log1p(capacity + 2) / (item + 2)
        else:
            priorities[i] += np.tanh(capacity / (item + 1))
        if i % 5 == 0 and priorities[i] < 10:
            priorities[i] += sum(1 / (capacity + k + 1) for k in range(3))
    return priorities
